header_year_regex = re.compile(r"(?:CHI|UbiComp|CSCW|DIS|PervasiveHealth|WWW|IUI|OzCHI|TEI|AH|ACM|IEEE)\s*(?:20)?16|Copyright\s*(?:©)?\s*2016|©\s*2016", re.IGNORECASE)

