    if not pa_pattern.search(text):
        continue

    # Check header (first 5000 chars)
    header = text[:5000]
    
    # If header contains 2017, 2018, 2015 etc. in the venue line, we might have a false positive if we also find 2016 (unlikely in header, but possible).
