    if header_year_regex.search(header):
        # Additional check: exclude if it looks like a citation? 
        # But in first 5000 chars, citations are rare unless numeric [1].
        # The regex is specific to Venue Names or Copyright.
        titles_2016.append(filename.replace('.txt', ''))

